import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { DeductionItem, DeductionKind } from '../../../core/models';
import { formatCents, toCents } from '../../../core/money';

/** Wizard step 4 — itemized deduction components (standard is computed server-side). */
@Component({
  selector: 'app-deductions',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './deductions.component.html',
  styleUrl: './deductions.component.css',
})
export class DeductionsComponent {
  returnId = '';

  // Mock data — service_agent clears this and loads via ApiService.listDeductions().
  deductions = signal<DeductionItem[]>([
    { id: 'x1', returnId: 'r-2024', kind: 'mortgage_interest', amountCents: 940000 },
    { id: 'x2', returnId: 'r-2024', kind: 'charity', amountCents: 120000 },
  ]);

  readonly kinds: { value: DeductionKind; label: string }[] = [
    { value: 'mortgage_interest', label: 'Mortgage interest' },
    { value: 'charity', label: 'Charitable gifts' },
    { value: 'salt', label: 'State & local taxes (SALT)' },
  ];

  readonly kindLabels: Record<DeductionKind, string> = {
    mortgage_interest: 'Mortgage interest',
    charity: 'Charitable gifts',
    salt: 'State & local taxes',
  };

  newKind: DeductionKind = 'mortgage_interest';
  newAmount: number | null = null;

  fmt = formatCents;

  constructor(private route: ActivatedRoute, private router: Router) {
    this.returnId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  }

  totalCents(): number {
    return this.deductions().reduce((sum, d) => sum + d.amountCents, 0);
  }

  add(): void {
    if (this.newAmount === null) return;
    this.deductions.update((list) => [
      ...list,
      {
        id: 'x' + (list.length + 1),
        returnId: this.returnId,
        kind: this.newKind,
        amountCents: toCents(this.newAmount ?? 0),
      },
    ]);
    this.newAmount = null;
  }

  remove(id: string): void {
    this.deductions.update((list) => list.filter((d) => d.id !== id));
  }

  back(): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', 'income']);
  }

  next(): void {
    this.router.navigate(['/returns', this.returnId, 'wizard', 'review']);
  }
}
